1	import express from 'express';
2	import cors from 'cors';
3	import { fileURLToPath } from 'node:url';
4	import { resolve, dirname, join } from 'node:path';
5	
6	const __dirname = dirname(fileURLToPath(import.meta.url));
7	
8	function createApp() {
9	  const app = express();
10	  const isProduction = process.env.NODE_ENV === 'production';
11	
12	  // ── Middleware ────────────────────────────────────────────────────────────
13	  // NOTE: origin:'*' + credentials:true is invalid per CORS spec (browsers reject it).
14	  // Use origin:true (reflect request Origin) in dev so credentials can coexist if needed.
15	  app.use(cors({
16	    origin: isProduction ? false : true, // 'true' reflects the request's Origin header
17	    credentials: true,
18	  }));
19	  app.use(express.json());
20	
21	  // ── Routes ────────────────────────────────────────────────────────────────
22	  app.get('/health', (_req, res) => res.json({ ok: true }));
23	
24	  // Dev/test-only routes (not in production)
25	  if (!isProduction) {
26	    app.post('/dev/echo', (req, res) => res.json(req.body));
27	    app.get('/dev/error', (req, res, next) => {
28	      const err = new Error('Test error');
29	      err.status = req.query.status ? parseInt(req.query.status, 10) : 500;
30	      next(err);
31	    });
32	  }
33	
34	  // ── Static files (production) ─────────────────────────────────────────────
35	  if (isProduction) {
36	    const distPath = join(__dirname, '..', 'client', 'dist');
37	    app.use(express.static(distPath));
38	    app.get('*', (_req, res) =>
39	      res.sendFile(join(distPath, 'index.html'))
40	    );
41	  }
42	
43	  // ── 404 handler ───────────────────────────────────────────────────────────
44	  app.use((_req, res) => res.status(404).json({ error: 'Not Found' }));
45	
46	  // ── Error handler ─────────────────────────────────────────────────────────
47	  // eslint-disable-next-line no-unused-vars
48	  app.use((err, _req, res, _next) => {
49	    const status = err.status || err.statusCode || 500;
50	    res.status(status).json({ error: err.message || 'Internal Server Error' });
51	  });
52	
53	  return app;
54	}
55	
56	// Start when run as the entry point
57	// resolve() normalises relative paths before comparing
58	if (resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
59	  const app = createApp();
60	  const PORT = process.env.PORT || 3001;
61	  app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
